With this change the crash is gone but the subsystem is added to the list of available controllers even when it is unavailable .
I think if os.Stat() fails the subsystem should be skipped.


```diff --git a/pkg/cgroups/cgroups.go b/pkg/cgroups/cgroups.go
--- a/pkg/cgroups/cgroups.go
+++ b/pkg/cgroups/cgroups.go
@@ -165,14 +165,13 @@ func getAvailableControllers(exclude map[string]controllerHandler, cgroup2 bool)
 		if _, found := exclude[name]; found {
 			continue
 		}
-		isSymLink := false
 		fileInfo, err := os.Stat(cgroupRoot + "/" + name)
 		if err != nil {
-			isSymLink = !fileInfo.IsDir()
+			continue
 		}
 		c := controller{
 			name:    name,
-			symlink: isSymLink,
+			symlink: !fileInfo.IsDir(),
 		}
 		controllers = append(controllers, c)
 	}
```
